#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n = 0;
    char choice = 'E';
    srand(1);
    printf("Numbers: * * * * *\n");
    printf("Pick a number: ");
    scanf("%d", &n);
    printf("Enter choice: ");
    scanf(" %c", &choice);
    printf("Guess choice %c, number %d\n", choice, n);
    printf("Tug War winner score points\n");
    printf("You win 5 points. winner\n");
    return 0;
}
